mapper.select:
select cr.cert_no as certNo, c.contest_name as contestName, p.name as holderName, s.award_level as awardLevel, c.group_levels as groupLevel, '竞赛通平台' as issueOrg, cr.issue_time as issueTime, cr.issue_time as issueDate, cr.issue_status as issueStatus from jst_cert_record cr left join jst_contest c on c.contest_id = cr.contest_id and c.del_flag = '0' left join jst_score_record s on s.score_id = cr.score_id and s.del_flag = '0' left join jst_participant p on p.participant_id = cr.participant_id and p.del_flag = '0'
cr.del_flag = '0'
and cr.cert_no = #{certNo}
and cr.verify_code = #{verifyCode}
order by cr.cert_id desc limit 1
